import { useState } from "react";
import { createClient } from "@supabase/supabase-js";

const SUPABASE_URL = "https://vwfokozrpmbzofgropit.supabase.co";
const SUPABASE_ANON_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZ3Zm9rb3pycG1iem9mZ3JvcGl0Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzg2OTMyMzEsImV4cCI6MjA5NDI2OTIzMX0.x3qEtumkwsrcLQcb4bobZ2tjmvAhEOWpDNnEp9GgBXI";
const BUCKET_NAME = "files"; // Change this to your bucket name if different

const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

export default function App() {
  const [uploadFile, setUploadFile] = useState(null);
  const [uploadStatus, setUploadStatus] = useState("");
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [fileContent, setFileContent] = useState("");
  const [viewingFile, setViewingFile] = useState("");
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file && file.type === "text/plain") {
      setUploadFile(file);
      setError("");
    } else {
      setError("Please select a .txt file.");
      setUploadFile(null);
    }
  };

  const handleUpload = async () => {
    if (!uploadFile) return;
    setIsUploading(true);
    setUploadStatus("");
    setError("");

    const fileName = `${Date.now()}_${uploadFile.name}`;

    const { error: uploadError } = await supabase.storage
      .from(BUCKET_NAME)
      .upload(fileName, uploadFile, { contentType: "text/plain" });

    if (uploadError) {
      setError(`Upload failed: ${uploadError.message}`);
    } else {
      setUploadStatus(`✓ "${uploadFile.name}" uploaded successfully!`);
      setUploadFile(null);
      document.getElementById("fileInput").value = "";
      await loadFiles();
    }
    setIsUploading(false);
  };

  const loadFiles = async () => {
    setIsLoading(true);
    const { data, error: listError } = await supabase.storage
      .from(BUCKET_NAME)
      .list();

    if (listError) {
      setError(`Failed to load files: ${listError.message}`);
    } else {
      setUploadedFiles(data || []);
    }
    setIsLoading(false);
  };

  const handleDownload = async (fileName) => {
    setError("");
    const { data, error: downloadError } = await supabase.storage
      .from(BUCKET_NAME)
      .download(fileName);

    if (downloadError) {
      setError(`Download failed: ${downloadError.message}`);
      return;
    }

    const text = await data.text();
    setFileContent(text);
    setViewingFile(fileName);
  };

  const handleDownloadToDevice = async (fileName) => {
    const { data, error: downloadError } = await supabase.storage
      .from(BUCKET_NAME)
      .download(fileName);

    if (downloadError) {
      setError(`Download failed: ${downloadError.message}`);
      return;
    }

    const url = URL.createObjectURL(data);
    const a = document.createElement("a");
    a.href = url;
    a.download = fileName.replace(/^\d+_/, "");
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div style={styles.page}>
      {/* Header */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <div style={styles.badge}>CS 3733</div>
          <h1 style={styles.title}>File Storage Demo</h1>
          <p style={styles.subtitle}>Software Engineering</p>
          <div style={styles.meta}>
            <span style={styles.metaItem}>Instructor: Prof. Wilson Wong</span>
            <span style={styles.metaDot}>·</span>
            <span style={styles.metaItem}>Final Project Component Demonstration</span>
          </div>
        </div>
      </header>

      <main style={styles.main}>
        {/* Upload Section */}
        <section style={styles.card}>
          <h2 style={styles.cardTitle}>
            <span style={styles.icon}>↑</span> Upload File
          </h2>
          <p style={styles.cardDesc}>Select a .txt file from your computer to upload to Supabase storage.</p>

          <div style={styles.uploadArea}>
            <input
              id="fileInput"
              type="file"
              accept=".txt"
              onChange={handleFileChange}
              style={styles.fileInput}
            />
            <label htmlFor="fileInput" style={styles.fileLabel}>
              {uploadFile ? `📄 ${uploadFile.name}` : "Choose a .txt file"}
            </label>
          </div>

          {error && <p style={styles.error}>{error}</p>}
          {uploadStatus && <p style={styles.success}>{uploadStatus}</p>}

          <button
            onClick={handleUpload}
            disabled={!uploadFile || isUploading}
            style={{
              ...styles.button,
              ...((!uploadFile || isUploading) ? styles.buttonDisabled : {}),
            }}
          >
            {isUploading ? "Uploading..." : "Upload to Supabase"}
          </button>
        </section>

        {/* Files Section */}
        <section style={styles.card}>
          <div style={styles.cardHeader}>
            <h2 style={styles.cardTitle}>
              <span style={styles.icon}>☁</span> Files in Storage
            </h2>
            <button onClick={loadFiles} style={styles.refreshBtn}>
              {isLoading ? "Loading..." : "Load Files"}
            </button>
          </div>
          <p style={styles.cardDesc}>Click "Load Files" to see all uploaded files. Click a file to view or download it.</p>

          {uploadedFiles.length === 0 ? (
            <div style={styles.emptyState}>
              No files loaded yet — click "Load Files" above.
            </div>
          ) : (
            <div style={styles.fileList}>
              {uploadedFiles.map((file) => (
                <div key={file.name} style={styles.fileRow}>
                  <span style={styles.fileName}>
                    📄 {file.name.replace(/^\d+_/, "")}
                  </span>
                  <div style={styles.fileActions}>
                    <button
                      onClick={() => handleDownload(file.name)}
                      style={styles.viewBtn}
                    >
                      View
                    </button>
                    <button
                      onClick={() => handleDownloadToDevice(file.name)}
                      style={styles.downloadBtn}
                    >
                      Download
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>

        {/* File Viewer */}
        {viewingFile && (
          <section style={styles.card}>
            <h2 style={styles.cardTitle}>
              <span style={styles.icon}>📄</span> {viewingFile.replace(/^\d+_/, "")}
            </h2>
            <pre style={styles.fileViewer}>{fileContent}</pre>
            <button onClick={() => { setViewingFile(""); setFileContent(""); }} style={styles.closeBtn}>
              Close
            </button>
          </section>
        )}
      </main>

      <footer style={styles.footer}>
        CS 3733 · Software Engineering · Prof. Wilson Wong · Final Project Component Demonstration
      </footer>
    </div>
  );
}

